function TabBar({ activeTab, onChange }) {
  const tabs = [
    { id: 'wallet', label: 'Кошелёк', icon: walletIcon },
    { id: 'trade', label: 'Торговля', icon: tradeIcon },
    { id: 'bonus', label: 'Бонусы', icon: bonusIcon },
    { id: 'history', label: 'История', icon: <HistoryIcon /> },
  ];

  const activeIndex = tabs.findIndex((t) => t.id === activeTab);
  const activeIndexSafe = activeIndex >= 0 ? activeIndex : 0;

  return (
    <div className="Zr9ao tab-bar-root" style={{ transform: 'translateY(0%)' }}>
      <div className="QgRSk TeTDS" role="tablist" aria-orientation="horizontal">
        <div className="Lcb0i Lcb0i">
          <div
            className="KaTw3"
            data-tabs-count="4"
            data-theme="material"
            tabIndex={0}
            style={{ '--active-index': activeIndexSafe }}
          >
            <div className="nK_WK tab-bar-pill tab-bar-pill--shine" aria-hidden="true" />
            <div className="yEKB7">
              {tabs.map((tab, index) => (
                <div
                  key={tab.id}
                  data-tab-id={tab.id}
                  data-first-tab={index === 0 ? 'true' : undefined}
                  data-last-tab={index === tabs.length - 1 ? 'true' : undefined}
                  data-tab-index={index}
                  data-theme="material"
                  className={`o7k40 ${activeTab === tab.id ? 'active' : ''}`}
                  data-active-tab={activeTab === tab.id ? '' : undefined}
                  role="tab"
                  aria-selected={activeTab === tab.id}
                  tabIndex={activeTab === tab.id ? 0 : -1}
                  onClick={() => {
                    if (window.Telegram?.WebApp?.HapticFeedback?.selectionChanged) {
                      window.Telegram.WebApp.HapticFeedback.selectionChanged();
                    }
                    onChange(tab.id);
                  }}
                >
                  <div className="LcPDp">
                    <div className="FJOWj">{tab.icon}</div>
                  </div>
                  <div
                    variant="caption3"
                    weight="medium"
                    align="center"
                    className="cpHhd FoW5G CF5m5 v1P4d"
                  >
                    {tab.label}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default TabBar;
